const form=document.querySelector("form"),handlePost=e=>{e.preventDefault(),inputs.forEach(input=>{input.classList.add("disabled")}),submit.disabled=!0,spinner.removeAttribute("hidden"),spinner.classList.add("spin"),setTimeout(()=>{e.target.submit()},1e3)};if(form){const inputs=form.querySelectorAll("input, textarea"),submit=form.querySelector("button"),spinner=form.nextElementSibling;form.addEventListener("submit",handlePost)}